const e=JSON.parse('{"key":"v-19f5025e","path":"/posts/Generator%E4%B8%8EIterator.html","title":"虽然一般不用但是懂了就懂了：Generator与Iterator","lang":"zh-CN","frontmatter":{"title":"虽然一般不用但是懂了就懂了：Generator与Iterator","isTimeLine":true,"date":"2026-01-15T00:00:00.000Z","category":["前端"],"tag":["JavaScript","源码"]},"headers":[{"level":2,"title":"Iterator","slug":"iterator","link":"#iterator","children":[{"level":3,"title":"是什么","slug":"是什么","link":"#是什么","children":[]},{"level":3,"title":"调用Iterator接口的场合","slug":"调用iterator接口的场合","link":"#调用iterator接口的场合","children":[]},{"level":3,"title":"工作原理","slug":"工作原理","link":"#工作原理","children":[]}]},{"level":2,"title":"Generator","slug":"generator","link":"#generator","children":[{"level":3,"title":"1. 是什么？","slug":"_1-是什么","link":"#_1-是什么","children":[]},{"level":3,"title":"与 Iterator 接口的关系","slug":"与-iterator-接口的关系","link":"#与-iterator-接口的关系","children":[]}]},{"level":2,"title":"链接","slug":"链接","link":"#链接","children":[]}],"git":{"createdTime":1773286516000,"updatedTime":1773286516000,"contributors":[{"name":"liunal","email":"liunal","commits":1}]},"readingTime":{"minutes":5.28,"words":1584},"filePathRelative":"posts/Generator与Iterator.md","localizedDate":"2026年1月15日","excerpt":"<h2> Iterator</h2>\\n<h3> 是什么</h3>\\n<ol>\\n<li>遍历器（Iterator），它是一种接口，为各种不同的数据结构提供统一的访问机制。任何数据结构只要具备Symbol.iterator属性，就可以被遍历。比如for...of循环遍历某种数据结构时，该循环会自动去寻找Iterator接口。</li>\\n<li>作用：1）是为各种数据结构，提供一个统一的、简便的访问接口；2）使得数据结构的成员能够按某种次序排列；3）Iterator接口主要供for...of消费。</li>\\n</ol>\\n<h3> 调用Iterator接口的场合</h3>\\n<blockquote>\\n<ul>\\n<li>解构赋值，对数组和Set结构进行解构赋值时，会默认调用Symbol.iterator方法。<code>let [first, ...rest] = set</code></li>\\n<li>还有扩展运算符<code>[...arr]</code>、<code>for...of</code>、<code>Array.from()</code>、<code>Map()</code>、<code>Set()</code>等</li>\\n</ul>\\n</blockquote>"}');export{e as data};
